#include "qp/labels/leakage_guard.hpp"
namespace qp::labels { LeakageGuard::LeakageGuard(LeakagePolicy p): policy_(p){} Result<void> LeakageGuard::validate(Timestamp sample, Timestamp start, Timestamp end) const { if(!(end>start)) return Err(Error{ErrorCode::InvalidArgument,"label end must be after label start"}); auto min_start=Timestamp{sample.value + policy_.prediction_gap}; if(policy_.require_strict_future){ if(!(start>min_start) && policy_.prediction_gap.count()==0) return Err(Error{ErrorCode::LeakageDetected,"label start must be strictly after sample timestamp"}); if(policy_.prediction_gap.count()!=0 && start<min_start) return Err(Error{ErrorCode::LeakageDetected,"prediction gap violated"}); } else if(start<min_start) return Err(Error{ErrorCode::LeakageDetected,"prediction gap violated"}); return Ok(); } }
